    const int lane_id = threadIdx.x % WARP_SIZE;

    const int tile_row = blockIdx.y * TILE_SIZE;
    const int tile_col = blockIdx.x * TILE_SIZE;

    const int bc_idx = blockIdx.z;
    const int b = bc_idx / channels;
    const int c = bc_idx % channels;

