__device__ inline void block_reduce(volatile float* shared_sum, int tid, int block_size) {
    for (int stride = block_size / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_sum[tid] += shared_sum[tid + stride];
        }
        __syncthreads();
    }
}

