            float r1 = (vec.y > 0.f) ? vec.y : alpha * (expf(vec.y) - 1.f);
            float r2 = (vec.z > 0.f) ? vec.z : alpha * (expf(vec.z) - 1.f);
            float r3 = (vec.w > 0.f) ? vec.w : alpha * (expf(vec.w) - 1.f);

