    float* shared_weight = shared_mem;
    float* shared_bias = &shared_mem[in_channels * out_channels * kernel_h * kernel_w];
    float* shared_reduce = &shared_mem[in_channels * out_channels * kernel_h * kernel_w + out_channels];

