    const int w_pool_out = idx % W_pool_out;
    int temp = idx / W_pool_out;
    const int h_pool_out = temp % H_pool_out;
    temp /= H_pool_out;
    const int c_out = temp % out_channels;
    const int n = temp / out_channels;

