    int remainder = num_elements % 4;
    int start = total_vec * 4;
    for (int i = idx; i < remainder; i += blockDim.x * gridDim.x) {
        int global_idx = start + i;
        int c = (global_idx / spatial_size) % channels;
        float orig = conv_output[global_idx];
