// Block reduction: sums values from all threads in a block
template <typename scalar_t>
__inline__ __device__ scalar_t blockReduceSum(scalar_t val) {
    __shared__ scalar_t shared[32]; // One per warp
    int lane = threadIdx.x % warpSize;
    int wid = threadIdx.x / warpSize;

    val = warpReduceSum(val);

    if (lane == 0) {
        shared[wid] = val;
    }
    __syncthreads();

    // Only first warp participates in final reduction
    val = (threadIdx.x < blockDim.x / warpSize) ? shared[lane] : static_cast<scalar_t>(0);
    if (wid == 0) {
        val = warpReduceSum(val);
    }
    return val;
}

// Fused kernel: performs group normalization, two swish activations and a multiplication
// The kernel is designed to work on a chunk of the batch where the host code shifts the pointer
// so that base_n can be set to 0.

template <typename scalar_t>
__global__ void fused_kernel(
    const scalar_t* __restrict__ x,
    scalar_t* __restrict__ output,
    const scalar_t* __restrict__ group_norm_weight,
    const scalar_t* __restrict__ group_norm_bias,
    const scalar_t* __restrict__ multiply_weight,
    const int C,
    const int channels_per_group,
    const int base_n  // batch offset, pointer shifted by host so typically 0
) {
    // Each block in x-direction corresponds to one sample in the chunk,
    // y-direction corresponds to one group
    int n = base_n + blockIdx.x; // sample index
    int g = blockIdx.y;           // group index
    int tid = threadIdx.x;

    __shared__ scalar_t mean_shared;
    __shared__ scalar_t var_shared;

    scalar_t sum = 0;
    scalar_t sumsq = 0;

    // Reduction: compute mean and variance for this group
    for (int c = tid; c < channels_per_group; c += blockDim.x) {
        int channel_idx = g * channels_per_group + c;
        int idx = n * C + channel_idx;
        // Use __ldg to leverage read-only cache
        scalar_t val = __ldg(&x[idx]);
        sum += val;
        sumsq += val * val;
    }

    sum = blockReduceSum(sum);
    sumsq = blockReduceSum(sumsq);

    if (threadIdx.x == 0) {
        mean_shared = sum / static_cast<scalar_t>(channels_per_group);
        var_shared = sumsq / static_cast<scalar_t>(channels_per_group) - mean_shared * mean_shared + static_cast<scalar_t>(1e-5);
    }
    __syncthreads();

    scalar_t mean = mean_shared;
    scalar_t inv_std = rsqrtf(var_shared);

    // For all channels in this group, normalize and apply swish activations
    for (int c = tid; c < channels_per_group; c += blockDim.x) {
        int channel_idx = g * channels_per_group + c;
        int idx = n * C + channel_idx;

        scalar_t v = x[idx];
        scalar_t gamma = group_norm_weight[channel_idx];
        scalar_t beta = group_norm_bias[channel_idx];
        scalar_t w = multiply_weight[channel_idx];

        // Group normalization: scale and shift
        scalar_t y = (v - mean) * inv_std;
        y = y * gamma + beta;

        // First Swish activation
        scalar_t sigmoid_y = 1.0f / (1.0f + expf(-y));
        y = y * sigmoid_y;

        // Multiply by additional weight
        y = y * w;

        // Second Swish activation
        sigmoid_y = 1.0f / (1.0f + expf(-y));
        y = y * sigmoid_y;

        output[idx] = y;
    }
