            const scalar_t x20 = x[x_base + (h_out + 2) * in_w + (w_out + 0)];
            const scalar_t x21 = x[x_base + (h_out + 2) * in_w + (w_out + 1)];
            const scalar_t x22 = x[x_base + (h_out + 2) * in_w + (w_out + 2)];

