    int stride = blockDim.x * gridDim.x;

    // Determine the largest multiple of 4 less than or equal to size
    int unroll_bound = (size / 4) * 4;

    // Main loop: Process 4 elements per thread using loop unrolling
    for (int i = tid * 4; i < unroll_bound; i += stride * 4) {
