        scalar_t v1 = x_data[i + 1];
        scalar_t v2 = x_data[i + 2];
        scalar_t v3 = x_data[i + 3];

        v0 = sigmoid(v0);
        v1 = sigmoid(v1);
        v2 = sigmoid(v2);
        v3 = sigmoid(v3);

        x_data[i]     = v0 * scaling_factor + original_x_data[i];
        x_data[i + 1] = v1 * scaling_factor + original_x_data[i + 1];
        x_data[i + 2] = v2 * scaling_factor + original_x_data[i + 2];
        x_data[i + 3] = v3 * scaling_factor + original_x_data[i + 3];
    }

    // Remainder loop for leftover elements
    // The starting index for remainder is offset by unroll_bound, adjusted per thread
    for (int i = tid * 4 + unroll_bound; i < size; i += stride) {
        scalar_t v = x_data[i];
        v = sigmoid(v);
        x_data[i] = v * scaling_factor + original_x_data[i];
