    const int b = blockIdx.z / out_channels;
    const int oh = blockIdx.y * blockDim.y + threadIdx.y;
    const int ow_base = blockIdx.x * WARP_SIZE + lane_id;

    // Early exit for out-of-bounds threads (uniform across warp)
