        warp_sums[0] = total_sum / cols;  // Store mean
    }
    __syncthreads();

    // Apply mean subtraction and GELU with minimal divergence
    const float mean = warp_sums[0];
    for (int col = tid; col < cols; col += blockDim.x) {
        float val = data[row * cols + col] - mean;
