    while (vec_idx < num_elements / VEC_SIZE) {
        const vec_t x_vec = __ldg(reinterpret_cast<const vec_t*>(x_conv) + vec_idx);
        const vec_t a_vec = __ldg(reinterpret_cast<const vec_t*>(add_input) + vec_idx);
        vec_t out_vec;

