    local_sum = __shfl_sync(0xffffffff, local_sum, 0);
    local_sumsq = __shfl_sync(0xffffffff, local_sumsq, 0);

    float mean = local_sum / channels_per_group;
    float var = local_sumsq / channels_per_group - mean * mean;
    float inv_std = rsqrtf(var + eps);

    #pragma unroll 4
    for (int i = tid * 4; i < channels_per_group; i += blockDim.x * 4) {
        if (i + 3 < channels_per_group) {
            float4 values;
            values.x = __ldg(&in[base_idx + i]);
            values.y = __ldg(&in[base_idx + i + 1]);
