    const float mean = s_mean;
    const float inv_std = s_inv_std;

    #pragma unroll 4
    for (int i = 0; i < vectors_per_thread; i++) {
        const int idx = tid + i * BLOCK_SIZE;
        if (idx < num_vectors) {
            float4 val4 = data4[idx];
