    // Final reduction from warp sums done by thread 0
    float group_mean = 0.0f;
    float group_inv_std = 0.0f;
    if (tid == 0) {
        int num_warps = (blockDim.x + 31) / 32;
        float sum_tot = 0.0f;
        float sum_sq_tot = 0.0f;
