// This kernel computes the per-location min reduction (over the channel dimension)
// and then sums across the height (H) dimension, writing results for each column (W) in the output.
// Global memory accesses are aligned and coalesced: threads in a warp access consecutive elements in W.

__global__ void fused_min_sum_kernel_coalesced(
    const float* __restrict__ input, 
    float* __restrict__ output, 
    int N, int C, int H, int W
) {
    // Each block processes a tile of the input for a single image (n)
    int n = blockIdx.x;  // image index
    int tile_h = blockIdx.y * TILE_H;
    int tile_w = blockIdx.z * TILE_W;

    int local_h = threadIdx.y;   // vertical index within the tile
    int local_w = threadIdx.x;   // horizontal index within the tile

    int global_h = tile_h + local_h;
    int global_w = tile_w + local_w;

    // Shared memory to hold the computed min values for the tile
    __shared__ float smem[TILE_H][TILE_W];

    float local_min = FLT_MAX;
    if (global_h < H && global_w < W) {
        // Compute min over channel dimension for location (n, global_h, global_w)
        #pragma unroll
        for (int c = 0; c < C; c++) {
            // Memory access is coalesced along the width dimension as global_w increases
            float val = input[((n * C + c) * H + global_h) * W + global_w];
            local_min = fminf(local_min, val);
        }
        smem[local_h][local_w] = local_min;
    } else {
        smem[local_h][local_w] = 0.0f;
    }
    __syncthreads();

    // Reduce vertically along the tile's height dimension for each column
    // Only one thread per column (local_h == 0) performs the reduction
    if (local_h == 0 && (tile_w + local_w) < W) {
        float col_sum = 0.0f;
        #pragma unroll
        for (int i = 0; i < TILE_H; i++) {
            if (tile_h + i < H) {
                col_sum += smem[i][local_w];
            }
        }
        // Write the partial sum to global memory using atomic add
        // Output tensor is of shape (N, 1, 1, W) and contiguous so we index as n * W + (tile_w + local_w)
        atomicAdd(&output[n * W + (tile_w + local_w)], col_sum);
    }
