__global__ void warp_rnn_kernel_aligned(
    const float * __restrict__ x,       // [batch_size, x_dim]
    const float * __restrict__ hidden,    // [batch_size, h_dim]
    const float * __restrict__ weight,    // [h_dim, (x_dim + h_dim)]
    const float * __restrict__ bias,      // [h_dim]
    float * __restrict__ hidden_new,      // [batch_size, h_dim]
    int batch_size,
    int x_dim,
    int h_dim
) {
