    int j = blockIdx.x * blockDim.y + threadIdx.y;  // hidden neuron index
    int lane = threadIdx.x;  // lane index within the warp (0-31)

    if (b >= batch_size || j >= h_dim) return;

    float sum = 0.0f;
    int weight_offset = j * (x_dim + h_dim);

    // Aligned vector loads for x dimension
    const float4* x_vec = reinterpret_cast<const float4*>(x + b * x_dim);
    const float4* w_vec = reinterpret_cast<const float4*>(weight + weight_offset);

    // Process x_dim in chunks of 4 floats using float4
    int x_vec_elements = x_dim / 4;
    for (int k = lane; k < x_vec_elements; k += 32) {
        float4 x_val = __ldg(&x_vec[k]);
        float4 w_val = __ldg(&w_vec[k]);

        sum += x_val.x * w_val.x + x_val.y * w_val.y + 
               x_val.z * w_val.z + x_val.w * w_val.w;
    }

    // Handle remaining x elements
    for (int k = x_dim - (x_dim % 4) + lane; k < x_dim; k += 32) {
        float x_val = __ldg(&x[b * x_dim + k]);
        float w_val = __ldg(&weight[weight_offset + k]);
        sum += x_val * w_val;
    }

    // Process hidden dimension with aligned loads where possible
    const float4* h_vec = reinterpret_cast<const float4*>(hidden + b * h_dim);
    const float4* wh_vec = reinterpret_cast<const float4*>(weight + weight_offset + x_dim);

    int h_vec_elements = h_dim / 4;
    for (int k = lane; k < h_vec_elements; k += 32) {
        float4 h_val = __ldg(&h_vec[k]);
        float4 w_val = __ldg(&wh_vec[k]);

        sum += h_val.x * w_val.x + h_val.y * w_val.y + 
               h_val.z * w_val.z + h_val.w * w_val.w;
    }

    // Handle remaining hidden elements
    for (int k = h_dim - (h_dim % 4) + lane; k < h_dim; k += 32) {
        float h_val = __ldg(&hidden[b * h_dim + k]);
        float w_val = __ldg(&weight[weight_offset + x_dim + k]);
        sum += h_val * w_val;
    }

    // Warp-level reduction using butterfly pattern
    #pragma unroll
    for (int offset = 16; offset > 0; offset /= 2) {
        sum += __shfl_down_sync(0xffffffff, sum, offset);
    }

