        /*stride=*/torch::IntArrayRef({(int64_t)stride, (int64_t)stride}),
        /*padding=*/torch::IntArrayRef({1, 1}),
        /*dilation=*/torch::IntArrayRef({1, 1}),
        /*groups=*/conv2_w.size(0) // depthwise
    );
