        /*input=*/x,
        /*weight=*/conv3_w,
        /*bias=*/c10::nullopt,
        /*stride=*/torch::IntArrayRef({1, 1}),
        /*padding=*/torch::IntArrayRef({0, 0}),
        /*dilation=*/torch::IntArrayRef({1, 1}),
        /*groups=*/1
    );
    x = at::batch_norm(
        x,
        conv3_bn_w, conv3_bn_b,
        conv3_bn_rm, conv3_bn_rv,
