  auto identity = x;

  // First conv block
  auto out = torch::conv2d(x, conv1_weight, {}, {stride, stride}, {1, 1});
  out = torch::batch_norm(out, bn1_weight, bn1_bias, bn1_mean, bn1_var, is_training, 0.1, 1e-5, true);
