  identity = torch::batch_norm(
      identity,
      downsample_bn_weight,
      downsample_bn_bias,
      downsample_bn_mean,
      downsample_bn_var,
      is_training,
      0.1,
      1e-5,
      true
  );

  // Add and final activation
  out += identity;
  out = torch::relu(out);

  return out;
}

